// ExampleV1Client is used to interact with features provided by the example.com/v1 group.
type ExampleV1Client struct {
	restClient rest.Interface
}

// Widgets returns a WidgetInterface for the given namespace.
func (c *ExampleV1Client) Widgets(namespace string) WidgetInterface {
	return newWidgets(c.restClient, namespace)
}

// RESTClient returns a RESTClient that is used to communicate
// with API server by this client implementation.
func (c *ExampleV1Client) RESTClient() rest.Interface {
	if c == nil {
		return nil
	}
	return c.restClient
}

// NewForConfig creates a new ExampleV1Client for the given config.
func NewForConfig(c *rest.Config) (*ExampleV1Client, error) {
	config := *c
	// Set the group version for the config
	config.GroupVersion = &metav1.GroupVersion{Group: "example.com", Version: "v1"}
	config.APIPath = "/apis"
	config.NegotiatedSerializer = rest.CodecFactoryForGeneratedClient(scheme.Scheme, scheme.Codecs).WithoutConversion()

	if config.UserAgent == "" {
		config.UserAgent = rest.DefaultKubernetesUserAgent()
	}

	client, err := rest.RESTClientFor(&config)
	if err != nil {
		return nil, err
	}
	return &ExampleV1Client{client}, nil
}

// New creates a new ExampleV1Client for the given RESTClient.
func New(c rest.Interface) *ExampleV1Client {
	return &ExampleV1Client{c}
}

